// Restaurant Business Analyzer for N8N - FIXED VERSION
// Input: JSON data with orders, menu components, and inventory

// Get all input data
const inputData = $input.all();

// Helper function to parse items string
function parseOrderItems(itemsString) {
    if (!itemsString) return [];
    const lines = itemsString.split('\\n');
    return lines.map(line => {
        const match = line.match(/(\d+)x\s+(.+)/);
        if (match) {
            return {
                quantity: parseInt(match[1]),
                name: match[2].trim()
            };
        }
        return null;
    }).filter(item => item !== null);
}

// Extract all items from input data
let allItems = [];
inputData.forEach(item => {
    if (item.json) {
        allItems.push(item.json);
    }
});

// If input is directly the array, use it
if (allItems.length === 0) {
    allItems = inputData;
}

console.log(`Total input items: ${allItems.length}`);

// Separate data types
const orders = [];
const menuComponents = [];
const inventory = [];

allItems.forEach(item => {
    if (item.order_ID) {
        orders.push(item);
    } else if (item.menuItem) {
        menuComponents.push(item);
    } else if (item.Item) {
        inventory.push(item);
    }
});

console.log(`Orders: ${orders.length}, Menu: ${menuComponents.length}, Inventory: ${inventory.length}`);

// Filter successful orders (exclude cancelled)
const successfulOrders = orders.filter(order => 
    order.status && order.status.toLowerCase() !== 'cancelled'
);

// Filter cancelled orders
const cancelledOrders = orders.filter(order => 
    order.status && order.status.toLowerCase() === 'cancelled'
);

console.log(`Total orders: ${orders.length}`);
console.log(`Successful orders: ${successfulOrders.length}`);
console.log(`Cancelled orders: ${cancelledOrders.length}`);

// Calculate gross sales (before discounts)
let grossSales = 0;
let totalDiscounts = 0;

successfulOrders.forEach(order => {
    const price = parseFloat(order.totalPrice) || 0;
    const discount = parseFloat(order.discount) || 0;

    grossSales += price;
    totalDiscounts += discount;
});

console.log(`Gross Sales: ${grossSales}`);
console.log(`Total Discounts: ${totalDiscounts}`);

// Net sales = gross sales - discounts
const netSales = grossSales - totalDiscounts;

// Analyze orders by type
const dineInOrders = successfulOrders.filter(order => 
    order.orderType && order.orderType.toLowerCase() === 'dine-in'
);
const deliveryOrders = successfulOrders.filter(order => 
    order.orderType && order.orderType.toLowerCase() === 'delivery'
);

const dineInRevenue = dineInOrders.reduce((sum, order) => 
    sum + (parseFloat(order.totalPrice) || 0), 0
);
const deliveryRevenue = deliveryOrders.reduce((sum, order) => 
    sum + (parseFloat(order.totalPrice) || 0), 0
);

console.log(`Dine-in: ${dineInOrders.length} orders, ${dineInRevenue} EGP`);
console.log(`Delivery: ${deliveryOrders.length} orders, ${deliveryRevenue} EGP`);

// Calculate cancelled orders revenue (potential lost revenue)
let cancelledRevenue = 0;
const cancelledOrdersByType = {
    dineIn: 0,
    delivery: 0
};

cancelledOrders.forEach(order => {
    const revenue = parseFloat(order.totalPrice) || 0;
    cancelledRevenue += revenue;

    if (order.orderType && order.orderType.toLowerCase() === 'dine-in') {
        cancelledOrdersByType.dineIn++;
    } else if (order.orderType && order.orderType.toLowerCase() === 'delivery') {
        cancelledOrdersByType.delivery++;
    }
});

console.log(`Cancelled orders: ${cancelledOrders.length} orders, ${cancelledRevenue} EGP potential lost revenue`);

// Count items sold
const itemCounts = {};
const itemRevenue = {};

successfulOrders.forEach(order => {
    const items = parseOrderItems(order.items);
    const orderTotal = parseFloat(order.totalPrice) || 0;
    const orderDiscount = parseFloat(order.discount) || 0;
    const orderNetTotal = orderTotal - orderDiscount; // Use net total for item revenue calculation
    const itemsInOrder = items.reduce((sum, item) => sum + item.quantity, 0);

    items.forEach(item => {
        if (!itemCounts[item.name]) {
            itemCounts[item.name] = 0;
            itemRevenue[item.name] = 0;
        }
        itemCounts[item.name] += item.quantity;

        // Estimate revenue per item (proportional to order net total)
        if (itemsInOrder > 0) {
            const itemProportion = item.quantity / itemsInOrder;
            itemRevenue[item.name] += orderNetTotal * itemProportion;
        }
    });
});

console.log(`Item types found: ${Object.keys(itemCounts).length}`);

// Calculate COGS
function calculateCOGS() {
    let totalCOGS = 0;

    // Create inventory lookup
    const inventoryLookup = {};
    inventory.forEach(item => {
        inventoryLookup[item.Item] = parseFloat(item.price) || 0;
    });

    // Create menu components lookup
    const menuLookup = {};
    menuComponents.forEach(item => {
        if (item.components) {
            const components = item.components.split(', ').map(comp => {
                const match = comp.match(/(\d+(?:\.\d+)?)([a-zA-Z]+)\s+(.+)/);
                if (match) {
                    return {
                        quantity: parseFloat(match[1]),
                        unit: match[2],
                        ingredient: match[3]
                    };
                }
                // Handle simple format like "1x Burger Bun"
                const simpleMatch = comp.match(/(\d+)x\s+(.+)/);
                if (simpleMatch) {
                    return {
                        quantity: parseInt(simpleMatch[1]),
                        unit: 'piece',
                        ingredient: simpleMatch[2]
                    };
                }
                return null;
            }).filter(comp => comp !== null);

            menuLookup[item.menuItem] = components;
        }
    });

    // Calculate COGS for each sold item
    Object.keys(itemCounts).forEach(itemName => {
        const quantitySold = itemCounts[itemName];
        const components = menuLookup[itemName];

        if (components) {
            components.forEach(component => {
                const ingredientPrice = inventoryLookup[component.ingredient];
                if (ingredientPrice) {
                    let costPerUnit = 0;

                    // Simple cost calculation based on component quantity
                    if (component.unit === 'piece' || component.unit === 'can' || component.unit === 'bottle') {
                        costPerUnit = ingredientPrice * component.quantity;
                    } else if (component.unit === 'g' && component.quantity <= 200) {
                        // Convert grams to kg pricing
                        costPerUnit = (ingredientPrice / 1000) * component.quantity;
                    } else if (component.unit === 'ml' && component.quantity <= 100) {
                        // Convert ml to liter pricing  
                        costPerUnit = (ingredientPrice / 1000) * component.quantity;
                    } else {
                        // Default calculation
                        costPerUnit = ingredientPrice * (component.quantity / 100);
                    }

                    totalCOGS += costPerUnit * quantitySold;
                }
            });
        }
    });

    return Math.round(totalCOGS * 100) / 100; // Round to 2 decimal places
}

const totalCOGS = calculateCOGS();

// FIXED CALCULATIONS
const grossProfit = netSales - totalCOGS; // Should be based on net sales, not gross
const netProfit = grossProfit; // Since we already deducted discounts

console.log(`COGS: ${totalCOGS}`);
console.log(`Net Sales: ${netSales}`);
console.log(`Gross Profit (corrected): ${grossProfit}`);
console.log(`Net Profit: ${netProfit}`);

// Order status analysis
const orderStatuses = {};
orders.forEach(order => {
    const status = order.status || 'unknown';
    orderStatuses[status] = (orderStatuses[status] || 0) + 1;
});

// Top selling items (based on corrected revenue calculation)
const topItems = Object.keys(itemCounts)
    .map(item => ({
        name: item,
        quantity: itemCounts[item],
        revenue: Math.round(itemRevenue[item] * 100) / 100
    }))
    .sort((a, b) => b.revenue - a.revenue)
    .slice(0, 10);

// Calculate FIXED percentages and averages
const avgOrderValue = successfulOrders.length > 0 ? Math.round((netSales / successfulOrders.length) * 100) / 100 : 0;
const dineInNetRevenue = dineInRevenue - (dineInOrders.reduce((sum, order) => sum + (parseFloat(order.discount) || 0), 0));
const deliveryNetRevenue = deliveryRevenue - (deliveryOrders.reduce((sum, order) => sum + (parseFloat(order.discount) || 0), 0));
const dineInAOV = dineInOrders.length > 0 ? Math.round((dineInNetRevenue / dineInOrders.length) * 100) / 100 : 0;
const deliveryAOV = deliveryOrders.length > 0 ? Math.round((deliveryNetRevenue / deliveryOrders.length) * 100) / 100 : 0;
const successRate = orders.length > 0 ? Math.round((successfulOrders.length / orders.length) * 100 * 100) / 100 : 0;
const profitMargin = netSales > 0 ? Math.round((netProfit / netSales) * 100 * 100) / 100 : 0;

// FIXED: Revenue efficiency based on net sales
const potentialNetRevenue = netSales + (cancelledRevenue - cancelledOrders.reduce((sum, order) => sum + (parseFloat(order.discount) || 0), 0));
const revenueEfficiency = potentialNetRevenue > 0 ? Math.round((netSales / potentialNetRevenue) * 100 * 100) / 100 : 0;

// Prepare final output with CORRECTED values
const businessSummary = {
    reportDate: new Date().toISOString().split('T')[0],
    totalOrders: orders.length,
    successfulOrders: successfulOrders.length,
    cancelledOrders: cancelledOrders.length,

    // Financial Summary - CORRECTED
    financial: {
        grossSales: Math.round(grossSales * 100) / 100,
        totalDiscounts: Math.round(totalDiscounts * 100) / 100,
        netSales: Math.round(netSales * 100) / 100,
        costOfGoodsSold: totalCOGS,
        grossProfit: Math.round(grossProfit * 100) / 100, // FIXED: Now based on net sales
        netProfit: Math.round(netProfit * 100) / 100,
        profitMarginPercent: profitMargin, // FIXED: Now correctly calculated
        cancelledRevenue: Math.round(cancelledRevenue * 100) / 100,
        potentialTotalRevenue: Math.round((grossSales + cancelledRevenue) * 100) / 100
    },

    // Order Type Analysis - CORRECTED
    orderTypes: {
        dineIn: {
            count: dineInOrders.length,
            revenue: Math.round(dineInNetRevenue * 100) / 100, // FIXED: Net revenue
            percentage: orders.length > 0 ? Math.round((dineInOrders.length / orders.length) * 100 * 100) / 100 : 0,
            averageOrderValue: dineInAOV // FIXED: Based on net revenue
        },
        delivery: {
            count: deliveryOrders.length,
            revenue: Math.round(deliveryNetRevenue * 100) / 100, // FIXED: Net revenue
            percentage: orders.length > 0 ? Math.round((deliveryOrders.length / orders.length) * 100 * 100) / 100 : 0,
            averageOrderValue: deliveryAOV // FIXED: Based on net revenue
        }
    },

    // Performance Metrics - CORRECTED
    performance: {
        averageOrderValue: avgOrderValue, // FIXED: Based on net sales
        successRate: successRate,
        cancellationRate: Math.round((cancelledOrders.length / orders.length) * 100 * 100) / 100,
        revenueEfficiency: revenueEfficiency // FIXED: Based on net sales
    },

    // Order Status Breakdown
    orderStatuses: orderStatuses,

    // Cancelled Orders Analysis
    cancelledAnalysis: {
        totalCancelledOrders: cancelledOrders.length,
        cancelledRevenue: Math.round(cancelledRevenue * 100) / 100,
        cancelledPercentage: orders.length > 0 ? Math.round((cancelledOrders.length / orders.length) * 100 * 100) / 100 : 0,
        cancelledByType: {
            dineIn: cancelledOrdersByType.dineIn,
            delivery: cancelledOrdersByType.delivery
        },
        averageCancelledOrderValue: cancelledOrders.length > 0 ? Math.round((cancelledRevenue / cancelledOrders.length) * 100) / 100 : 0,
        cancelledOrderDetails: cancelledOrders.map(order => ({
            orderId: order.order_ID,
            orderType: order.orderType,
            customerName: order.customerName,
            totalPrice: parseFloat(order.totalPrice) || 0,
            items: order.items,
            createdAt: order.createdAt,
            updatedAt: order.updatedAt
        }))
    },

    // Top Selling Items - Now based on net revenue
    topSellingItems: topItems,

    // All Items Summary - CORRECTED
    itemsSummary: Object.keys(itemCounts).map(item => ({
        name: item,
        quantitySold: itemCounts[item],
        estimatedRevenue: Math.round(itemRevenue[item] * 100) / 100,
        revenuePercentage: netSales > 0 ? Math.round((itemRevenue[item] / netSales) * 100 * 100) / 100 : 0 // FIXED: Based on net sales
    })).sort((a, b) => b.estimatedRevenue - a.estimatedRevenue),

    // Debug info
    debug: {
        totalInputItems: allItems.length,
        ordersFound: orders.length,
        menuItemsFound: menuComponents.length,
        inventoryItemsFound: inventory.length
    }
};

// Add discount analysis
if (totalDiscounts > 0) {
    const discountedOrders = successfulOrders.filter(order => 
        parseFloat(order.discount || 0) > 0
    );

    businessSummary.discounts = {
        totalAmount: Math.round(totalDiscounts * 100) / 100,
        ordersCount: discountedOrders.length,
        percentage: Math.round((totalDiscounts / grossSales) * 100 * 100) / 100,
        averageDiscountPerOrder: discountedOrders.length > 0 ? 
            Math.round((totalDiscounts / discountedOrders.length) * 100) / 100 : 0
    };
}

console.log('Analysis completed successfully with CORRECTED calculations');

// Return the analysis results
return businessSummary;
